/**
 * Cached economic enrichment (generated by npm run enrich:economic).
 */

import countryEconomicsJson from './country-economics.json';
import cityEconomicsJson from './city-economics-by-geonameid.json';
import metaJson from './enrichment-meta.json';

let _country = null;
let _city = null;

export function loadCountryEconomics() {
  if (!_country) _country = countryEconomicsJson;
  return _country;
}

export function loadCityEconomicsByGeonameId() {
  if (!_city) _city = cityEconomicsJson;
  return _city;
}

export function getEnrichmentMeta() {
  return metaJson;
}

export function getCountryEconomics(iso2) {
  if (!iso2) return null;
  return loadCountryEconomics()[iso2] ?? null;
}

export function getCityEconomics(geonameid) {
  if (geonameid == null) return null;
  return loadCityEconomicsByGeonameId()[String(geonameid)] ?? null;
}

/**
 * Merge base world city row with cached economics + route-model fields.
 * @param {import('../worldCities.js').WorldCity} city
 */
export function enrichWorldCityRecord(city) {
  const econ = getCityEconomics(city.geonameid);
  const iso2 = econ?.countryIso2 ?? null;
  const country = iso2 ? getCountryEconomics(iso2) : null;

  const latitude = econ?.latitude ?? city.latitude ?? null;
  const longitude = econ?.longitude ?? city.longitude ?? null;
  const population = econ?.population ?? city.population ?? null;

  return {
    ...city,
    countryIso2: iso2,
    latitude,
    longitude,
    hasCoordinates: latitude != null && longitude != null,
    population,
    gdp: econ?.gdpEstimateUsd ?? null,
    gdpPerCapitaUsd: econ?.gdpPerCapitaUsd ?? country?.gdpPerCapitaUsd ?? null,
    businessTravelers: econ?.businessTravelers ?? 0,
    airportCapacity: econ?.airportCapacity ?? 100,
    regulatoryEase: econ?.regulatoryEase ?? 0.55,
    geopoliticalStability: econ?.geopoliticalStability ?? 0.55,
    tier: inferTier(population, econ?.gdpEstimateUsd),
    continent: country?.region ?? null,
    incomeLevel: country?.incomeLevel ?? null,
  };
}

function inferTier(population, gdpEstimate) {
  if ((population ?? 0) >= 5_000_000 || (gdpEstimate ?? 0) >= 50_000_000_000) return '1A';
  if ((population ?? 0) >= 1_000_000 || (gdpEstimate ?? 0) >= 10_000_000_000) return '1B';
  return '1C';
}

/** Shape expected by src/routeModel */
export function toRouteModelCity(enriched) {
  const code =
    enriched.countryIso2 && enriched.geonameid
      ? `${enriched.countryIso2}_${enriched.geonameid}`
      : `GN_${enriched.geonameid ?? enriched.id}`;

  return {
    code: code.slice(0, 12),
    name: enriched.name,
    country: enriched.country,
    tier: enriched.tier ?? '1C',
    latitude: enriched.latitude,
    longitude: enriched.longitude,
    population: enriched.population ?? 0,
    gdp: enriched.gdp ?? 0,
    businessTravelers: enriched.businessTravelers ?? 0,
    airportCapacity: enriched.airportCapacity ?? 100,
    regulatoryEase: enriched.regulatoryEase ?? 0.55,
    geopoliticalStability: enriched.geopoliticalStability ?? 0.55,
    geonameid: enriched.geonameid,
    countryIso2: enriched.countryIso2,
  };
}

export async function loadEnrichedWorldCitiesForModel({ requireCoordinates = false, minPopulation = 0 } = {}) {
  const { loadWorldCities } = await import('../worldCities.js');
  const cities = loadWorldCities()
    .map(enrichWorldCityRecord)
    .filter((c) => {
      if (requireCoordinates && !c.hasCoordinates) return false;
      if (minPopulation && (c.population ?? 0) < minPopulation) return false;
      return c.latitude != null && c.longitude != null;
    })
    .map(toRouteModelCity);
  return cities;
}
